package com.interview.incidentrca.service;
import com.interview.incidentrca.dto.*;import com.interview.incidentrca.enums.*;import com.interview.incidentrca.mapper.IncidentMapper;import com.interview.incidentrca.repository.*;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.*;import org.springframework.stereotype.Service;import java.time.Duration;import java.util.*;
@Service @RequiredArgsConstructor public class AnalyticsService{private final IncidentRepository incidents;private final AuditLogRepository audits;private final IncidentMapper mapper; public List<CountResponse> severity(){return Arrays.stream(Severity.values()).map(s->new CountResponse(s.name(),incidents.countBySeverity(s))).toList();} public List<CountResponse> status(){return Arrays.stream(IncidentStatus.values()).map(s->new CountResponse(s.name(),incidents.countByStatus(s))).toList();} public List<CountResponse> topServices(){Map<String,Long> m=new HashMap<>();incidents.findAll().forEach(i->m.merge(i.getServiceComponent().getName(),1L,Long::sum));return m.entrySet().stream().sorted(Map.Entry.<String,Long>comparingByValue().reversed()).limit(5).map(e->new CountResponse(e.getKey(),e.getValue())).toList();} public Map<String,Object> slaBreaches(){long breached=incidents.findAll().stream().filter(i->i.getResolvedAt()!=null&&Duration.between(i.getCreatedAt(),i.getResolvedAt()).toHours()> switch(i.getSeverity()){case CRITICAL->1;case HIGH->4;case MEDIUM->12;case LOW->24;}).count();double avg=incidents.findAll().stream().filter(i->i.getResolvedAt()!=null).mapToLong(i->Duration.between(i.getCreatedAt(),i.getResolvedAt()).toMinutes()).average().orElse(0);return Map.of("slaBreachCount",breached,"averageResolutionMinutes",Math.round(avg));} public Page<AuditLogResponse> audit(Pageable p){return audits.findAll(p).map(mapper::toAudit);} }
